"use client"

import * as React from "react"
import {
    Badge,
    Button,
    Card,
    CardContent,
    CardHeader,
    CardTitle,
    DataTable,
    Delta,
    Meter,
    Select,
    Separator,
    Sheet,
    SheetClose,
    SheetContent,
    SheetDescription,
    SheetFooter,
    SheetHeader,
    SheetTitle,
    Statistic,
    Tabs,
    TabsContent,
    TabsList,
    TabsTrigger,
    Tag,
    cn,
    formatNumber,
    type ColumnDef,
} from "@gunjo/ui"

import { ProductionGantt } from "./ProductionGantt"
import { LoadMatrix } from "./LoadMatrix"
import {
    DAYS,
    LINES,
    ORDERS,
    PLANNING_HORIZON_DAYS,
    computeLoadMatrix,
    dueState,
    hoursPerDay,
    slackDays,
    type DueState,
    type Order,
    type Priority,
} from "./data"

const PRIORITY_META: Record<Priority, { label: string; variant: "destructive" | "secondary" | "outline" }> = {
    high: { label: "高", variant: "destructive" },
    normal: { label: "中", variant: "secondary" },
    low: { label: "低", variant: "outline" },
}

const STATUS_META: Record<
    Order["status"],
    { label: string; variant: "secondary" | "info" | "success" }
> = {
    unassigned: { label: "未割付", variant: "secondary" },
    assigned: { label: "割付済", variant: "info" },
    "in-progress": { label: "着手", variant: "success" },
}

const DUE_META: Record<DueState, { label: string; variant: "success" | "warning" | "destructive" }> = {
    "on-time": { label: "納期内", variant: "success" },
    "at-risk": { label: "ぎりぎり", variant: "warning" },
    late: { label: "納期遅れ", variant: "destructive" },
}

export default function ProductionPlanningPage() {
    const [orders, setOrders] = React.useState<Order[]>(ORDERS)
    const [selectedOrderId, setSelectedOrderId] = React.useState<string | null>(null)
    const [sheetOpen, setSheetOpen] = React.useState(false)
    // Re-plan form state
    const [draftLineId, setDraftLineId] = React.useState<string>("")
    const [draftStartDay, setDraftStartDay] = React.useState<number>(0)
    const [draftSpan, setDraftSpan] = React.useState<number>(1)

    const load = React.useMemo(() => computeLoadMatrix(orders, LINES), [orders])
    const dueStateOf = React.useCallback((o: Order) => dueState(o), [])

    const selectedOrder = orders.find((o) => o.id === selectedOrderId) ?? null

    // KPI roll-ups
    const counts = React.useMemo(() => {
        let late = 0
        let atRisk = 0
        let unassigned = 0
        for (const o of orders) {
            if (o.status === "unassigned") unassigned++
            const d = dueState(o)
            if (d === "late") late++
            else if (d === "at-risk") atRisk++
        }
        const onTime = orders.length - late - atRisk
        const adherence = Math.round((onTime / orders.length) * 100)
        return { late, atRisk, unassigned, onTime, adherence, total: orders.length }
    }, [orders])

    // Over-capacity cell count (山積みオーバー)
    const overCapacityCells = React.useMemo(() => {
        let n = 0
        for (const line of LINES) {
            for (const h of load[line.id] ?? []) {
                if (h > line.capacityPerDay) n++
            }
        }
        return n
    }, [load])

    // Preview of the pending re-plan move for the LoadMatrix striped overlay.
    const incomingPreview = React.useMemo(() => {
        if (!sheetOpen || !selectedOrder || !draftLineId) return undefined
        const per = selectedOrder.requiredHours / draftSpan
        const map: Record<string, number[]> = {
            [draftLineId]: new Array(PLANNING_HORIZON_DAYS).fill(0),
        }
        for (let d = draftStartDay; d < draftStartDay + draftSpan && d < PLANNING_HORIZON_DAYS; d++) {
            map[draftLineId][d] += per
        }
        return map
    }, [sheetOpen, selectedOrder, draftLineId, draftStartDay, draftSpan])

    function openReplan(order: Order) {
        setSelectedOrderId(order.id)
        setDraftLineId(order.lineId ?? LINES[0].id)
        setDraftStartDay(order.startDay ?? 0)
        setDraftSpan(order.startDay !== null && order.endDay !== null ? order.endDay - order.startDay + 1 : 1)
        setSheetOpen(true)
    }

    function applyReplan() {
        if (!selectedOrder) return
        const endDay = Math.min(draftStartDay + draftSpan - 1, PLANNING_HORIZON_DAYS - 1)
        setOrders((prev) =>
            prev.map((o) =>
                o.id === selectedOrder.id
                    ? {
                          ...o,
                          lineId: draftLineId,
                          startDay: draftStartDay,
                          endDay,
                          status: o.status === "in-progress" ? "in-progress" : "assigned",
                      }
                    : o
            )
        )
        setSheetOpen(false)
    }

    // ---- DataTable columns (backlog / 製造オーダ一覧) ----
    const columns = React.useMemo<ColumnDef<Order>[]>(
        () => [
            {
                accessorKey: "id",
                header: "製番",
                cell: ({ row }) => <span className="font-medium tabular-nums">{row.original.id}</span>,
            },
            { accessorKey: "partNo", header: "品番" },
            {
                accessorKey: "productName",
                header: "品名",
                cell: ({ row }) => <span className="whitespace-nowrap">{row.original.productName}</span>,
            },
            {
                accessorKey: "quantity",
                header: "数量",
                cell: ({ row }) => (
                    <span className="tabular-nums">
                        {formatNumber(row.original.quantity)}
                        <span className="ml-0.5 text-xs text-muted-foreground">{row.original.unit}</span>
                    </span>
                ),
            },
            {
                accessorKey: "requiredHours",
                header: "所要(h)",
                cell: ({ row }) => <span className="tabular-nums">{row.original.requiredHours}h</span>,
            },
            {
                accessorKey: "dueDate",
                header: "納期",
                cell: ({ row }) => {
                    const o = row.original
                    const slack = slackDays(o)
                    return (
                        <div className="flex flex-col gap-0.5">
                            <span className="tabular-nums">{o.dueDate.slice(5).replace("-", "/")}</span>
                            {slack !== null ? (
                                <Delta
                                    value={slack}
                                    hideArrow
                                    format={(d) => `${Math.abs(d)}日`}
                                    tones={{ positive: "success", negative: "destructive", zero: "warning" }}
                                    labels={{ positive: "余裕", negative: "超過", zero: "当日" }}
                                    showLabel
                                    className="text-xs"
                                />
                            ) : (
                                <span className="text-xs text-muted-foreground">未計画</span>
                            )}
                        </div>
                    )
                },
            },
            {
                accessorKey: "priority",
                header: "優先度",
                cell: ({ row }) => {
                    const p = PRIORITY_META[row.original.priority]
                    return <Tag variant={p.variant}>{p.label}</Tag>
                },
            },
            {
                accessorKey: "status",
                header: "割付状況",
                cell: ({ row }) => {
                    const s = STATUS_META[row.original.status]
                    return <Badge variant={s.variant}>{s.label}</Badge>
                },
            },
            {
                id: "due",
                header: "納期判定",
                cell: ({ row }) => {
                    const d = DUE_META[dueState(row.original)]
                    return <Badge variant={d.variant}>{d.label}</Badge>
                },
            },
            {
                id: "actions",
                header: "操作",
                cell: ({ row }) => (
                    <Button
                        size="xs"
                        variant="outline"
                        onClick={() => openReplan(row.original)}
                        aria-label={`${row.original.id} を再計画`}
                    >
                        {row.original.status === "unassigned" ? "割付" : "再計画"}
                    </Button>
                ),
            },
        ],
        // openReplan/dueState are stable enough for this demo
        []
    )

    // Rows needing attention get a tinted background (late = destructive, unassigned = warning).
    const getRowState = React.useCallback((o: Order) => {
        if (dueState(o) === "late") return "destructive"
        if (o.status === "unassigned") return "warning"
        return undefined
    }, [])

    return (
        <main className="mx-auto w-full max-w-[1280px] px-4 py-6 sm:px-6 lg:px-8">
            <header className="mb-6">
                <p className="text-xs font-medium text-muted-foreground">生産管理 / 工程</p>
                <h1 className="mt-1 text-2xl font-bold tracking-tight sm:text-3xl">
                    生産計画・負荷山積み
                </h1>
                <p className="mt-1 text-sm text-muted-foreground">
                    第2工場 ／ 計画期間 6/23（月）〜 6/28（土）。ライン別にオーダを割付け、負荷と能力のバランスを調整します。
                </p>
            </header>

            {/* KPI row */}
            <section aria-label="計画サマリー" className="mb-6 grid grid-cols-2 gap-3 sm:grid-cols-4">
                <Statistic
                    label="納期遵守率"
                    value={`${counts.adherence}%`}
                    change={`${counts.onTime}/${counts.total} 件 納期内`}
                    trend={counts.adherence >= 80 ? "up" : "down"}
                    tone={counts.adherence >= 80 ? "positive" : "negative"}
                />
                <Statistic
                    label="納期遅れ"
                    value={`${counts.late} 件`}
                    change={counts.atRisk > 0 ? `ぎりぎり ${counts.atRisk} 件` : "リスクなし"}
                    trend={counts.late > 0 ? "down" : "flat"}
                    tone={counts.late > 0 ? "negative" : "neutral"}
                />
                <Statistic
                    label="能力超過セル"
                    value={`${overCapacityCells}`}
                    change={overCapacityCells > 0 ? "山積みオーバー" : "問題なし"}
                    trend={overCapacityCells > 0 ? "down" : "flat"}
                    tone={overCapacityCells > 0 ? "negative" : "neutral"}
                    hint="（ライン×日）"
                />
                <Statistic
                    label="未割付オーダ"
                    value={`${counts.unassigned} 件`}
                    change="バックログ"
                    trend="flat"
                    tone="neutral"
                />
            </section>

            {/* Gantt + load tabs */}
            <Tabs defaultValue="gantt" className="mb-6 border-0">
                <TabsList>
                    <TabsTrigger value="gantt">計画ガント</TabsTrigger>
                    <TabsTrigger value="load">
                        負荷 vs 能力
                        {overCapacityCells > 0 ? (
                            <Badge variant="destructive" className="ml-2">
                                {overCapacityCells}
                            </Badge>
                        ) : null}
                    </TabsTrigger>
                </TabsList>

                <TabsContent value="gantt" className="px-0">
                    <ProductionGantt
                        lines={LINES}
                        orders={orders}
                        dueStateOf={dueStateOf}
                        selectedOrderId={selectedOrderId}
                        onSelectOrder={openReplan}
                    />
                    <p className="mt-2 text-xs text-muted-foreground">
                        バーをクリックすると再計画パネルが開きます。バーの色と左端のストライプ・ツールチップで納期状況を示します（色のみに依存しません）。
                    </p>
                </TabsContent>

                <TabsContent value="load" className="px-0">
                    <LoadMatrix lines={LINES} load={load} />
                    <p className="mt-2 text-xs text-muted-foreground">
                        各セルは <span className="font-medium text-foreground">計画負荷 ÷ 能力</span>。
                        80%以上で警告（黄）、100%超で「能力超過」（赤・「↑」表示）。色のみに依存しない表記です。
                    </p>
                </TabsContent>
            </Tabs>

            {/* Due-date adherence detail */}
            <section aria-label="納期遵守状況" className="mb-6">
                <h2 className="mb-3 text-lg font-semibold tracking-tight">納期・遵守状況</h2>
                <div className="grid gap-3 sm:grid-cols-3">
                    {(["late", "at-risk", "on-time"] as DueState[]).map((state) => {
                        const meta = DUE_META[state]
                        const list = orders.filter((o) => dueState(o) === state)
                        const toneBorder =
                            state === "late"
                                ? "border-destructive-border"
                                : state === "at-risk"
                                  ? "border-warning-border"
                                  : "border-success-border"
                        return (
                            <Card key={state} className={cn("border", toneBorder)}>
                                <CardHeader className="flex-row items-center justify-between gap-2 space-y-0">
                                    <CardTitle as="h3" className="text-base">
                                        {meta.label}
                                    </CardTitle>
                                    <Badge variant={meta.variant}>{list.length} 件</Badge>
                                </CardHeader>
                                <CardContent className="space-y-2">
                                    {list.length === 0 ? (
                                        <p className="text-sm text-muted-foreground">該当なし</p>
                                    ) : (
                                        list.slice(0, 4).map((o) => {
                                            const slack = slackDays(o)
                                            return (
                                                <div
                                                    key={o.id}
                                                    className="flex items-center justify-between gap-2 text-sm"
                                                >
                                                    <span className="min-w-0 truncate">
                                                        <span className="font-medium tabular-nums">{o.id}</span>
                                                        <span className="ml-1 text-muted-foreground">
                                                            {o.productName}
                                                        </span>
                                                    </span>
                                                    {slack !== null ? (
                                                        <Delta
                                                            value={slack}
                                                            hideArrow
                                                            format={(d) => `${Math.abs(d)}日`}
                                                            tones={{
                                                                positive: "success",
                                                                negative: "destructive",
                                                                zero: "warning",
                                                            }}
                                                            labels={{ positive: "余裕", negative: "超過", zero: "当日" }}
                                                            showLabel
                                                            className="shrink-0 text-xs"
                                                        />
                                                    ) : (
                                                        <span className="shrink-0 text-xs text-muted-foreground">
                                                            未割付
                                                        </span>
                                                    )}
                                                </div>
                                            )
                                        })
                                    )}
                                </CardContent>
                            </Card>
                        )
                    })}
                </div>
            </section>

            {/* Backlog / order table */}
            <section aria-label="製造オーダ一覧">
                <h2 className="mb-3 text-lg font-semibold tracking-tight">製造オーダ一覧</h2>
                <DataTable
                    columns={columns}
                    data={orders}
                    filter={{ columnId: "productName", placeholder: "品名で絞り込み…" }}
                    pageSize={10}
                    getRowState={getRowState}
                    onRowClick={(o) => openReplan(o)}
                    labels={{
                        filterPlaceholder: "品名で絞り込み…",
                        noResults: "該当するオーダがありません",
                        rowsPerPage: "表示件数",
                        previous: "前へ",
                        next: "次へ",
                    }}
                />
            </section>

            {/* Re-plan sheet */}
            <Sheet open={sheetOpen} onOpenChange={setSheetOpen}>
                <SheetContent side="right" className="flex w-full flex-col gap-0 sm:max-w-md">
                    <SheetHeader>
                        <SheetTitle>再計画 — オーダ割付</SheetTitle>
                        <SheetDescription>
                            {selectedOrder
                                ? `${selectedOrder.id}・${selectedOrder.productName}（所要 ${selectedOrder.requiredHours}h）をラインと期間に割付けます。`
                                : "オーダを選択してください。"}
                        </SheetDescription>
                    </SheetHeader>

                    {selectedOrder ? (
                        <div className="flex-1 space-y-5 overflow-y-auto py-4">
                            <div className="flex flex-wrap gap-2">
                                <Tag variant={PRIORITY_META[selectedOrder.priority].variant}>
                                    優先度 {PRIORITY_META[selectedOrder.priority].label}
                                </Tag>
                                <Badge variant={STATUS_META[selectedOrder.status].variant}>
                                    {STATUS_META[selectedOrder.status].label}
                                </Badge>
                                <Badge variant={DUE_META[dueState(selectedOrder)].variant}>
                                    納期 {selectedOrder.dueDate.slice(5).replace("-", "/")}
                                </Badge>
                            </div>

                            <Select
                                label="割付ライン"
                                value={draftLineId}
                                onChange={(e) => setDraftLineId(e.target.value)}
                            >
                                {LINES.map((l) => (
                                    <option key={l.id} value={l.id}>
                                        {l.name}（能力 {l.capacityPerDay}h/日）
                                    </option>
                                ))}
                            </Select>

                            <div className="grid grid-cols-2 gap-3">
                                <Select
                                    label="開始日"
                                    value={String(draftStartDay)}
                                    onChange={(e) => setDraftStartDay(Number(e.target.value))}
                                >
                                    {DAYS.map((d, i) => (
                                        <option key={d} value={i}>
                                            {d}曜
                                        </option>
                                    ))}
                                </Select>
                                <Select
                                    label="期間（日数）"
                                    value={String(draftSpan)}
                                    onChange={(e) => setDraftSpan(Number(e.target.value))}
                                >
                                    {[1, 2, 3, 4].map((n) => (
                                        <option key={n} value={n}>
                                            {n}日
                                        </option>
                                    ))}
                                </Select>
                            </div>

                            <Separator />

                            {/* Capacity preview for the chosen line — Meter with `incoming` */}
                            <div className="space-y-2">
                                <p className="text-sm font-medium">割付後の負荷プレビュー（{draftLineLabel(draftLineId)}）</p>
                                <p className="text-xs text-muted-foreground">
                                    縞模様が今回の追加分（{(selectedOrder.requiredHours / draftSpan).toFixed(1)}h/日）。能力超過は赤＋「↑」で表示。
                                </p>
                                <div className="space-y-3 rounded-md border bg-muted/20 p-3">
                                    {previewDays(draftStartDay, draftSpan).map((day) => {
                                        const line = LINES.find((l) => l.id === draftLineId)!
                                        // base load excluding this order on the target day
                                        const base = baseLoadExcluding(orders, selectedOrder.id, draftLineId, day, LINES)
                                        const inc = selectedOrder.requiredHours / draftSpan
                                        return (
                                            <Meter
                                                key={day}
                                                label={`${DAYS[day]}曜`}
                                                value={base}
                                                incoming={inc}
                                                max={line.capacityPerDay}
                                                unit="h"
                                                direction="higher-is-worse"
                                            />
                                        )
                                    })}
                                </div>
                            </div>
                        </div>
                    ) : null}

                    <SheetFooter className="gap-2">
                        <SheetClose asChild>
                            <Button variant="outline">キャンセル</Button>
                        </SheetClose>
                        <Button variant="primary" onClick={applyReplan} disabled={!selectedOrder || !draftLineId}>
                            この計画を適用
                        </Button>
                    </SheetFooter>
                </SheetContent>
            </Sheet>
        </main>
    )
}

// --- helpers used only by the page ---

function draftLineLabel(lineId: string): string {
    return LINES.find((l) => l.id === lineId)?.name ?? "—"
}

function previewDays(start: number, span: number): number[] {
    const days: number[] = []
    for (let d = start; d < start + span && d < PLANNING_HORIZON_DAYS; d++) days.push(d)
    return days
}

/** Planned load on a line/day from all orders EXCEPT the one being moved. */
function baseLoadExcluding(
    orders: Order[],
    excludeId: string,
    lineId: string,
    day: number,
    lines: typeof LINES
): number {
    let total = 0
    for (const o of orders) {
        if (o.id === excludeId) continue
        if (o.lineId !== lineId || o.startDay === null || o.endDay === null) continue
        if (day < o.startDay || day > o.endDay) continue
        total += hoursPerDay(o)
    }
    return total
}

// Domain data + helpers for the 生産計画 / 負荷山積み screen.
// Pure data — no @gunjo/ui imports here.

export type AssignStatus = "unassigned" | "assigned" | "in-progress"
export type Priority = "high" | "normal" | "low"

/** A manufacturing line / work center (設備・ライン). */
export interface Line {
    id: string
    name: string
    /** Daily available capacity in hours (能力, h/日). */
    capacityPerDay: number
}

/** A production order (製造オーダ). */
export interface Order {
    id: string // 製番
    partNo: string // 品番
    productName: string // 品名
    quantity: number // 数量
    unit: string // 単位
    /** Required processing time in hours (所要時間, h). */
    requiredHours: number
    /** Due date — ISO date string (納期). */
    dueDate: string
    priority: Priority
    status: AssignStatus
    /** Assigned line id, or null when 未割付. */
    lineId: string | null
    /** Day index (0-based, within the planning window) the job starts. null = 未割付. */
    startDay: number | null
    /** Day index (inclusive) the job ends. null = 未割付. */
    endDay: number | null
}

/** Planning window: one shift-week. Day 0 = 月. */
export const DAYS = ["月", "火", "水", "木", "金", "土"] as const
export const DAY_DATES = ["6/23", "6/24", "6/25", "6/26", "6/27", "6/28"] as const
export const TODAY_DAY_INDEX = 1 // 火曜が現在（"今"ライン用）

export const LINES: Line[] = [
    { id: "L1", name: "第1ライン（旋盤）", capacityPerDay: 16 },
    { id: "L2", name: "第2ライン（フライス）", capacityPerDay: 16 },
    { id: "L3", name: "第3ライン（研削）", capacityPerDay: 8 },
    { id: "L4", name: "組立ライン", capacityPerDay: 24 },
]

