export const PLANNING_HORIZON_DAYS = DAYS.length

/** Distribute an order's required hours evenly across its day span. */
export function hoursPerDay(order: Order): number {
    if (order.startDay === null || order.endDay === null) return 0
    const span = order.endDay - order.startDay + 1
    return order.requiredHours / span
}

/** Planned load (h) per line per day, summing all assigned orders. */
export function computeLoadMatrix(orders: Order[], lines: Line[]): Record<string, number[]> {
    const matrix: Record<string, number[]> = {}
    for (const line of lines) matrix[line.id] = new Array(PLANNING_HORIZON_DAYS).fill(0)
    for (const o of orders) {
        if (o.lineId === null || o.startDay === null || o.endDay === null) continue
        const per = hoursPerDay(o)
        for (let d = o.startDay; d <= o.endDay && d < PLANNING_HORIZON_DAYS; d++) {
            if (!matrix[o.lineId]) continue
            matrix[o.lineId][d] += per
        }
    }
    return matrix
}

/** The last calendar date (inclusive) covered by the plan for an order. */
export function plannedFinishDate(order: Order): string | null {
    if (order.endDay === null) return null
    // Day 0 maps to 2026-06-23; add endDay days. Use UTC math so the result is
    // not shifted across a date boundary by the local timezone (JST is UTC+9,
    // and toISOString() converts to UTC — that would eat the +1 day). (#self)
    const base = Date.UTC(2026, 5, 23) + order.endDay * 86_400_000
    return new Date(base).toISOString().slice(0, 10)
}

export type DueState = "on-time" | "at-risk" | "late"

/**
 * Due-date adherence. `late` = unassigned past/at due, or planned finish after
 * due. `at-risk` = planned finish lands on the due date (no slack) or unassigned
 * with <=1 day slack. Otherwise on-time.
 */
function isoToUtc(iso: string): number {
    const [y, m, d] = iso.split("-").map(Number)
    return Date.UTC(y, m - 1, d)
}

export function dueState(order: Order, todayIso = "2026-06-24"): DueState {
    const due = isoToUtc(order.dueDate)
    const today = isoToUtc(todayIso)
    const dayMs = 86_400_000

    if (order.status === "unassigned" || order.startDay === null) {
        // Not yet scheduled: late if already past due, at-risk if due within a day.
        if (due < today) return "late"
        if (due - today <= dayMs) return "at-risk"
        return "on-time"
    }

    const finishIso = plannedFinishDate(order)
    if (!finishIso) return "on-time"
    const finish = isoToUtc(finishIso)
    if (finish > due) return "late"
    if (finish === due) return "at-risk"
    return "on-time"
}

/** Slack in days between due date and planned finish (negative = late). */
export function slackDays(order: Order): number | null {
    const finishIso = plannedFinishDate(order)
    if (!finishIso) return null
    const due = isoToUtc(order.dueDate)
    const finish = isoToUtc(finishIso)
    return Math.round((due - finish) / 86_400_000)
}

