// 負荷 vs 能力 (load vs capacity per period). Built on @gunjo/ui <Meter> —
// a component designed for warehouse fill / truck load / quota that bends
// cleanly onto line-vs-capacity: direction="higher-is-worse" makes over
// destructive, thresholds flag near-full, and the % readout shows "↑" on
// overflow so 能力超過 never rides on colour alone. `incoming` previews a
// pending re-plan move.

import * as React from "react"
import { Meter, Badge, cn } from "@gunjo/ui"
import type { Line } from "./data"
import { DAYS, DAY_DATES, PLANNING_HORIZON_DAYS } from "./data"

export interface LoadMatrixProps {
    lines: Line[]
    /** lineId -> per-day planned load (hours). */
    load: Record<string, number[]>
    /**
     * Optional pending move preview: lineId -> per-day incoming hours, shown as
     * the striped <Meter incoming> overlay so a reviewer sees the result of a
     * re-plan before committing.
     */
    incoming?: Record<string, number[]>
}

export function LoadMatrix({ lines, load, incoming }: LoadMatrixProps) {
    return (
        <div className="min-w-0 overflow-x-auto rounded-lg border bg-card">
            <table className="w-full min-w-[44rem] border-collapse text-sm">
                <caption className="sr-only">
                    ライン別・日別の負荷（計画工数）と能力。能力超過のセルは赤系で「↑」付き。
                </caption>
                <thead>
                    <tr className="border-b bg-muted/40 text-xs text-muted-foreground">
                        <th scope="col" className="px-3 py-2 text-left font-semibold">
                            設備・ライン
                        </th>
                        {DAYS.map((d, i) => (
                            <th key={d} scope="col" className="border-l px-2 py-2 text-center font-semibold">
                                {d}
                                <span className="ml-1 font-normal">{DAY_DATES[i]}</span>
                            </th>
                        ))}
                    </tr>
                </thead>
                <tbody>
                    {lines.map((line) => {
                        const row = load[line.id] ?? new Array(PLANNING_HORIZON_DAYS).fill(0)
                        const inc = incoming?.[line.id]
                        return (
                            <tr key={line.id} className="border-b last:border-0">
                                <th
                                    scope="row"
                                    className="border-r bg-muted/20 px-3 py-3 text-left align-middle"
                                >
                                    <div className="text-sm font-medium text-foreground">{line.name}</div>
                                    <div className="text-xs text-muted-foreground tabular-nums">
                                        能力 {line.capacityPerDay}h/日
                                    </div>
                                </th>
                                {row.map((hours, day) => {
                                    const over = hours > line.capacityPerDay
                                    const incHours = inc?.[day] ?? 0
                                    return (
                                        <td
                                            key={day}
                                            className={cn(
                                                "border-l px-2 py-2 align-middle",
                                                over && "bg-destructive-subtle/40"
                                            )}
                                        >
                                            <div className="flex flex-col items-stretch gap-1">
                                                <Meter
                                                    value={hours}
                                                    max={line.capacityPerDay}
                                                    incoming={incHours > 0 ? incHours : undefined}
                                                    unit="h"
                                                    size="inline"
                                                    direction="higher-is-worse"
                                                    label={`${line.name} ${DAYS[day]} 負荷`}
                                                />
                                                <span className="text-center text-[11px] tabular-nums text-muted-foreground">
                                                    {hours.toFixed(1)}/{line.capacityPerDay}h
                                                </span>
                                                {over ? (
                                                    <Badge variant="destructive" className="mx-auto">
                                                        能力超過
                                                    </Badge>
                                                ) : null}
                                            </div>
                                        </td>
                                    )
                                })}
                            </tr>
                        )
                    })}
                </tbody>
            </table>
        </div>
    )
}

