// 計画ガント (multi-line production Gantt) — HAND-ROLLED.
// @gunjo/ui ships SegmentTimelineCard (single-row, time-axis, Card-wrapped) but
// NO multi-row / multi-resource scheduler with a shared time axis. So the grid
// itself (line rows sharing one day axis) is hand-built. We still compose
// @gunjo/ui primitives inside: Badge, Tooltip, cn — and reuse the same
// position math the library uses ((t-min)/range*100).

import * as React from "react"
import {
    Badge,
    Tooltip,
    TooltipContent,
    TooltipTrigger,
    cn,
} from "@gunjo/ui"
import type { Line, Order, Priority } from "./data"
import { DAYS, DAY_DATES, PLANNING_HORIZON_DAYS, TODAY_DAY_INDEX, hoursPerDay } from "./data"

const PRIORITY_LABEL: Record<Priority, string> = {
    high: "高",
    normal: "中",
    low: "低",
}

// Bar fill keyed to due state so over-deadline jobs read without relying on hue
// alone (also carries an icon/label in the tooltip + a left status stripe).
const DUE_BAR: Record<
    "on-time" | "at-risk" | "late",
    { bar: string; stripe: string; srLabel: string }
> = {
    "on-time": {
        bar: "bg-info-subtle text-info-subtle-foreground border-info-border",
        stripe: "bg-info-strong",
        srLabel: "納期内",
    },
    "at-risk": {
        bar: "bg-warning-subtle text-warning-subtle-foreground border-warning-border",
        stripe: "bg-warning-strong",
        srLabel: "納期ぎりぎり",
    },
    late: {
        bar: "bg-destructive-subtle text-destructive-subtle-foreground border-destructive-border",
        stripe: "bg-destructive-strong",
        srLabel: "納期遅れ",
    },
}

// Position helper — identical in spirit to SegmentTimelineCard.getSegmentPosition.
function dayToPercent(day: number) {
    return (day / PLANNING_HORIZON_DAYS) * 100
}

export interface ProductionGanttProps {
    lines: Line[]
    orders: Order[]
    dueStateOf: (o: Order) => "on-time" | "at-risk" | "late"
    selectedOrderId: string | null
    onSelectOrder: (order: Order) => void
}

export function ProductionGantt({
    lines,
    orders,
    dueStateOf,
    selectedOrderId,
    onSelectOrder,
}: ProductionGanttProps) {
    return (
        <div className="min-w-0 overflow-x-auto rounded-lg border bg-card">
            {/* min width keeps day columns legible on phones; the card scrolls. */}
            <div className="min-w-[44rem]">
                {/* Day-axis header */}
                <div
                    className="grid border-b bg-muted/40"
                    style={{ gridTemplateColumns: `12rem repeat(${PLANNING_HORIZON_DAYS}, 1fr)` }}
                >
                    <div className="px-3 py-2 text-xs font-semibold text-muted-foreground">
                        設備・ライン
                    </div>
                    {DAYS.map((d, i) => (
                        <div
                            key={d}
                            className={cn(
                                "border-l px-2 py-2 text-center text-xs font-semibold",
                                i === TODAY_DAY_INDEX ? "text-foreground" : "text-muted-foreground"
                            )}
                        >
                            <span>{d}</span>
                            <span className="ml-1 font-normal text-muted-foreground">{DAY_DATES[i]}</span>
                            {i === TODAY_DAY_INDEX ? (
                                <span className="ml-1 text-[10px] font-semibold text-primary">今日</span>
                            ) : null}
                        </div>
                    ))}
                </div>

                {/* Line rows */}
                <ol className="divide-y" aria-label="ライン別 計画ガント">
                    {lines.map((line) => {
                        const lineOrders = orders.filter(
                            (o) => o.lineId === line.id && o.startDay !== null && o.endDay !== null
                        )
                        return (
                            <li
                                key={line.id}
                                className="grid"
                                style={{ gridTemplateColumns: `12rem 1fr` }}
                            >
                                {/* Row header: line name + capacity */}
                                <div className="flex flex-col justify-center border-r bg-muted/20 px-3 py-3">
                                    <span className="text-sm font-medium text-foreground">{line.name}</span>
                                    <span className="text-xs text-muted-foreground tabular-nums">
                                        能力 {line.capacityPerDay}h/日
                                    </span>
                                </div>

                                {/* Track: grid lines + today marker + positioned bars */}
                                <div className="relative h-16">
                                    {/* day gridlines */}
                                    <div
                                        className="absolute inset-0 grid"
                                        style={{
                                            gridTemplateColumns: `repeat(${PLANNING_HORIZON_DAYS}, 1fr)`,
                                        }}
                                        aria-hidden
                                    >
                                        {DAYS.map((d, i) => (
                                            <div key={d} className={cn(i > 0 && "border-l border-border/60")} />
                                        ))}
                                    </div>

                                    {/* 「今」line (dashed vertical marker — same idea as SegmentTimelineCard markers) */}
                                    <div
                                        className="pointer-events-none absolute inset-y-0 z-20 w-px border-l border-dashed border-primary/70"
                                        style={{ left: `${dayToPercent(TODAY_DAY_INDEX + 0.5)}%` }}
                                        aria-hidden
                                    />

                                    {/* job bars */}
                                    {lineOrders.map((o) => {
                                        const start = o.startDay as number
                                        const end = o.endDay as number
                                        const left = dayToPercent(start)
                                        const width = dayToPercent(end - start + 1)
                                        const due = dueStateOf(o)
                                        const cfg = DUE_BAR[due]
                                        const selected = selectedOrderId === o.id
                                        const perDay = hoursPerDay(o)
                                        return (
                                            <Tooltip key={o.id}>
                                                <TooltipTrigger asChild>
                                                    <button
                                                        type="button"
                                                        onClick={() => onSelectOrder(o)}
                                                        aria-pressed={selected}
                                                        className={cn(
                                                            "absolute top-1/2 z-10 flex h-10 -translate-y-1/2 items-center gap-1.5 overflow-hidden rounded-md border pl-2 pr-2 text-left text-xs transition-shadow",
                                                            "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:ring-offset-background",
                                                            cfg.bar,
                                                            selected && "ring-2 ring-foreground ring-offset-1 ring-offset-background"
                                                        )}
                                                        style={{
                                                            left: `calc(${left}% + 3px)`,
                                                            width: `calc(${width}% - 6px)`,
                                                        }}
                                                        aria-label={`${o.id} ${o.productName}、${line.name}、${DAYS[start]}〜${DAYS[end]}、所要 ${o.requiredHours}時間、${cfg.srLabel}`}
                                                    >
                                                        {/* status stripe — meaning not on colour alone */}
                                                        <span
                                                            aria-hidden
                                                            className={cn("absolute inset-y-0 left-0 w-1", cfg.stripe)}
                                                        />
                                                        <span className="ml-1 truncate font-semibold">{o.id}</span>
                                                        <span className="truncate text-[11px] opacity-80">
                                                            {o.productName}
                                                        </span>
                                                    </button>
                                                </TooltipTrigger>
                                                <TooltipContent>
                                                    <div className="space-y-0.5 text-left">
                                                        <p className="font-semibold">
                                                            {o.id}・{o.productName}
                                                        </p>
                                                        <p className="text-xs">
                                                            品番 {o.partNo} / {o.quantity.toLocaleString()}
                                                            {o.unit}
                                                        </p>
                                                        <p className="text-xs tabular-nums">
                                                            所要 {o.requiredHours}h（{perDay.toFixed(1)}h/日）・優先度
                                                            {PRIORITY_LABEL[o.priority]}
                                                        </p>
                                                        <p className="text-xs">納期 {o.dueDate}・{cfg.srLabel}</p>
                                                    </div>
                                                </TooltipContent>
                                            </Tooltip>
                                        )
                                    })}

                                    {lineOrders.length === 0 ? (
                                        <span className="absolute inset-0 flex items-center justify-center text-xs text-muted-foreground">
                                            割付なし
                                        </span>
                                    ) : null}
                                </div>
                            </li>
                        )
                    })}
                </ol>
            </div>

            {/* Legend — due-state encoding (icon/label, not colour only) */}
            <div className="flex flex-wrap items-center gap-3 border-t bg-muted/20 px-3 py-2 text-xs">
                <span className="text-muted-foreground">納期状況:</span>
                <Badge variant="info">納期内</Badge>
                <Badge variant="warning">ぎりぎり</Badge>
                <Badge variant="destructive">遅れ</Badge>
                <span className="ml-auto flex items-center gap-1 text-muted-foreground">
                    <span className="inline-block h-3 w-px border-l border-dashed border-primary/70" aria-hidden />
                    今日（{DAY_DATES[TODAY_DAY_INDEX]}）
                </span>
            </div>
        </div>
    )
}
